import{_ as a,a as e,b as d,c as o}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as i,o as r,c as n,a2 as s}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Додавання каналу WebDAV","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/upload/webdav.md","filePath":"uk-UA/upload/webdav.md","lastUpdated":1781962217000}'),l={name:"uk-UA/upload/webdav.md"};function p(c,t,h,b,u,m){return r(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="додавання-каналу-webdav" tabindex="-1">Додавання каналу WebDAV <a class="header-anchor" href="#додавання-каналу-webdav" aria-label="Permalink to &quot;Додавання каналу WebDAV&quot;">​</a></h1><h2 id="коли-це-наикращии-варіант" tabindex="-1">Коли це найкращий варіант <a class="header-anchor" href="#коли-це-наикращии-варіант" aria-label="Permalink to &quot;Коли це найкращий варіант&quot;">​</a></h2><p>Використовуйте канал WebDAV, якщо:</p><ul><li>у вас є NAS, хмарний диск або об&#39;єктне сховище з WebDAV endpoint;</li><li>хочете, щоб завантажені зображення зберігалися у вашій власній WebDAV-директорії;</li><li>хочете зберігати облікові дані в таблиці D1 <code>upload_channels</code>, а не тримати їх надовго відкритими на фронтенді.</li></ul><h2 id="що-підготувати-заздалегідь" tabindex="-1">Що підготувати заздалегідь <a class="header-anchor" href="#що-підготувати-заздалегідь" aria-label="Permalink to &quot;Що підготувати заздалегідь&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Потрібно</th><th>Навіщо це потрібно</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>Серверна WebDAV-адреса, наприклад <code>https://nas.example.com/dav</code>.</td></tr><tr><td>Username</td><td>Ім&#39;я користувача для входу у WebDAV-сервіс.</td></tr><tr><td>Password</td><td>Пароль для входу у WebDAV-сервіс.</td></tr><tr><td>Authentication mode</td><td>Типово <code>Basic</code>. Використовуйте <code>Digest</code> або автоматичне узгодження лише тоді, коли цього вимагає сервер.</td></tr><tr><td>Storage directory</td><td>Директорія для зберігання файлів. Типово <code>imgbed</code>.</td></tr></tbody></table><h2 id="де-додати-канал" tabindex="-1">Де додати канал <a class="header-anchor" href="#де-додати-канал" aria-label="Permalink to &quot;Де додати канал&quot;">​</a></h2><ol><li>Відкрийте системні налаштування.</li><li>Перейдіть до налаштувань завантаження.</li><li>Натисніть Add Channel у правому верхньому куті.</li><li>Виберіть <code>WebDAV</code>.</li></ol><h2 id="поля-налаштування" tabindex="-1">Поля налаштування <a class="header-anchor" href="#поля-налаштування" aria-label="Permalink to &quot;Поля налаштування&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Поле</th><th>Що означає</th><th>Обов&#39;язково</th></tr></thead><tbody><tr><td>Назва каналу</td><td>Зручна назва WebDAV-каналу, наприклад <code>koofr</code> або <code>nas</code>.</td><td>Так</td></tr><tr><td>Endpoint</td><td>Повний WebDAV endpoint, включно з <code>https://</code>.</td><td>Так</td></tr><tr><td>Username</td><td>Ім&#39;я користувача WebDAV.</td><td>Так</td></tr><tr><td>Password</td><td>Пароль WebDAV.</td><td>Так</td></tr><tr><td>Authentication mode</td><td>Зазвичай <code>Basic</code>; використовуйте <code>Digest</code>, якщо сервер вимагає digest authentication.</td><td>Так</td></tr><tr><td>Storage directory</td><td>Директорія, де зберігаються файли. Типово <code>imgbed</code>.</td><td>Ні</td></tr></tbody></table><h2 id="приклад-fie-nl-tab-digital" tabindex="-1">Приклад: fie.nl.tab.digital <a class="header-anchor" href="#приклад-fie-nl-tab-digital" aria-label="Permalink to &quot;Приклад: fie.nl.tab.digital&quot;">​</a></h2><h3 id="_1-створіть-app-password" tabindex="-1">1. Створіть app password <a class="header-anchor" href="#_1-створіть-app-password" aria-label="Permalink to &quot;1. Створіть app password&quot;">​</a></h3><p>Відкрийте налаштування безпеки облікового запису, знайдіть application passwords і створіть новий app password.</p><p><img src="'+a+'" alt="Створення app password" loading="lazy"></p><p>Після створення скопіюйте й збережіть новий app password. Зазвичай його показують лише один раз.</p><p><img src="'+e+'" alt="Збереження нового app password" loading="lazy"></p><h3 id="_2-заповніть-webdav-конфігурацію-в-imgbed" tabindex="-1">2. Заповніть WebDAV-конфігурацію в ImgBed <a class="header-anchor" href="#_2-заповніть-webdav-конфігурацію-в-imgbed" aria-label="Permalink to &quot;2. Заповніть WebDAV-конфігурацію в ImgBed&quot;">​</a></h3><p>Поверніться до ImgBed і додайте WebDAV-канал:</p><table tabindex="0"><thead><tr><th>Поле в інтерфейсі</th><th>Значення</th></tr></thead><tbody><tr><td>Endpoint</td><td>WebDAV URL, який надає <code>https://fie.nl.tab.digital/</code>.</td></tr><tr><td>Username</td><td>Ваш WebDAV username.</td></tr><tr><td>Password</td><td>App password, який ви щойно створили.</td></tr><tr><td>Authentication mode</td><td>У більшості випадків почніть із <code>Basic</code>.</td></tr><tr><td>Storage directory</td><td>Типово <code>imgbed</code>; за потреби можна вказати власну директорію.</td></tr></tbody></table><p><img src="'+d+'" alt="Заповнення конфігурації" loading="lazy"></p><h2 id="поведінка-під-час-завантаження-великих-фаилів" tabindex="-1">Поведінка під час завантаження великих файлів <a class="header-anchor" href="#поведінка-під-час-завантаження-великих-фаилів" aria-label="Permalink to &quot;Поведінка під час завантаження великих файлів&quot;">​</a></h2><p>Канал WebDAV використовує справжнє chunked upload на основі сесії.</p><p>Невеликі файли завантажуються як один цілісний файл. Файли понад 64 MiB автоматично діляться на частини приблизно по 10 MiB і завантажуються у віддалену директорію чанків.</p><p>WebDAV-сервісу не потрібно підтримувати <code>partial update</code> або запис за offset. ImgBed не зливає чанки в один великий файл на віддаленому сервері. Натомість він зберігає manifest чанків і читає їх по черзі, коли файл запитують.</p><p>На практиці:</p><table tabindex="0"><thead><tr><th>Розмір файлу</th><th>Спосіб завантаження</th><th>Структура у віддаленому сховищі</th></tr></thead><tbody><tr><td>64 MiB або менше</td><td>Звичайне завантаження</td><td>Один цілісний файл</td></tr><tr><td>Більше ніж 64 MiB</td><td>Справжнє session chunked upload</td><td>Директорія чанків із кількома файлами-частинами</td></tr></tbody></table><p>Директорія чанків впливає лише на структуру віддаленого сховища. Вона не змінює URL файлу в ImgBed. Користувачі й далі відкривають файл через початкове посилання <code>/file/...</code>.</p><h2 id="налаштування" tabindex="-1">Налаштування <a class="header-anchor" href="#налаштування" aria-label="Permalink to &quot;Налаштування&quot;">​</a></h2><ol><li>Відкрийте налаштування завантаження.</li><li>Натисніть Add Channel.</li><li>Виберіть <code>WebDAV</code>.</li><li>Введіть зрозумілу назву каналу, наприклад <code>koofr</code>.</li><li>Введіть WebDAV endpoint, наприклад <code>https://app.koofr.net/dav/Koofr</code>.</li><li>Введіть username і password.</li><li>За замовчуванням залиште authentication mode як <code>Basic</code>.</li><li>Залиште storage directory як <code>imgbed</code> або змініть на власну директорію.</li><li>Натисніть Save.</li><li>Після збереження перевірте картку каналу, за можливості запитайте місткість і завантажте тестовий файл.</li></ol><h2 id="як-перевірити" tabindex="-1">Як перевірити <a class="header-anchor" href="#як-перевірити" aria-label="Permalink to &quot;Як перевірити&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Перевірка</th><th>Як перевірити</th></tr></thead><tbody><tr><td>Картка каналу з&#39;явилася</td><td>Після збереження на сторінці налаштувань завантаження має бути картка WebDAV-каналу.</td></tr><tr><td>Канал увімкнений</td><td>Перемикач у правому верхньому куті картки має залишатися ввімкненим.</td></tr><tr><td>Облікові дані збережені</td><td>У деталях мають відображатися Endpoint, username, authentication mode і storage directory.</td></tr><tr><td>Невеликий файл завантажується</td><td>Завантажте тестове зображення й переконайтеся, що файл з&#39;явився у WebDAV-директорії.</td></tr><tr><td>Правило для великих файлів працює</td><td>Файли понад 64 MiB використовують chunked upload і створюють віддалену директорію чанків.</td></tr><tr><td>Запит місткості працює</td><td>Якщо сервер підтримує інформацію про місткість, запит покаже використаний і загальний обсяг.</td></tr></tbody></table><p><img src="'+o+`" alt="Успішний запит квоти" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="чому-великі-webdav-фаили-створюють-директорію-чанків" tabindex="-1">Чому великі WebDAV-файли створюють директорію чанків? <a class="header-anchor" href="#чому-великі-webdav-фаили-створюють-директорію-чанків" aria-label="Permalink to &quot;Чому великі WebDAV-файли створюють директорію чанків?&quot;">​</a></h3><p>Це поточний спосіб зберігання великих файлів.</p><p>Файли понад 64 MiB не зливаються в один великий віддалений файл. Вони зберігаються як директорія чанків. ImgBed записує manifest чанків і повертає повний вміст, читаючи частини по черзі.</p><h3 id="що-перевірити-насамперед-якщо-велике-завантаження-не-працює" tabindex="-1">Що перевірити насамперед, якщо велике завантаження не працює? <a class="header-anchor" href="#що-перевірити-насамперед-якщо-велике-завантаження-не-працює" aria-label="Permalink to &quot;Що перевірити насамперед, якщо велике завантаження не працює?&quot;">​</a></h3><p>Спочатку перевірте Endpoint, username, password і storage directory. Потім переконайтеся, що WebDAV-сервіс дозволяє створення директорій, запис файлів і читання файлів.</p><p>Якщо запит місткості не працює, але невеликий файл завантажується, сервер може просто не підтримувати або обмежувати звітування про місткість. Це не обов&#39;язково означає, що завантаження недоступне.</p><h3 id="якии-authentication-mode-вибрати" tabindex="-1">Який authentication mode вибрати? <a class="header-anchor" href="#якии-authentication-mode-вибрати" aria-label="Permalink to &quot;Який authentication mode вибрати?&quot;">​</a></h3><p>Почніть із <code>Basic</code>.</p><p>Якщо сервер прямо вимагає digest authentication, використовуйте <code>Digest</code>.</p><p>Якщо не впевнені, використовуйте автоматичне узгодження.</p><h2 id="короткии-чекліст" tabindex="-1">Короткий чекліст <a class="header-anchor" href="#короткии-чекліст" aria-label="Permalink to &quot;Короткий чекліст&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Підготувати WebDAV endpoint, username і password</span></span>
<span class="line"><span>-&gt; Відкрити налаштування завантаження</span></span>
<span class="line"><span>-&gt; Додати канал</span></span>
<span class="line"><span>-&gt; Вибрати WebDAV</span></span>
<span class="line"><span>-&gt; Ввести Endpoint / username / password</span></span>
<span class="line"><span>-&gt; Типово залишити authentication mode як Basic</span></span>
<span class="line"><span>-&gt; Типово залишити storage directory як imgbed</span></span>
<span class="line"><span>-&gt; Зберегти</span></span>
<span class="line"><span>-&gt; Запитати місткість</span></span>
<span class="line"><span>-&gt; Завантажити тестовий файл</span></span></code></pre></div>`,45)])])}const D=i(l,[["render",p]]);export{f as __pageData,D as default};
